import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ContentCategory {
  ALL = 'Tất cả',
  SERVICE = '1. Dịch vụ (Service Pages)',
  EDUCATIONAL = '2. Bệnh lý & Triệu chứng',
  PROMO = '3. Chi phí & Khuyến mãi',
  SOCIAL_PROOF = '4. Người thật việc thật',
  TIPS = '5. Hướng dẫn chăm sóc tại nhà',
  BRAND = '6. Thương hiệu & Đội ngũ',
  QA = '7. Hỏi đáp (Q&A)',
  PEDIATRIC = '8. Nha khoa trẻ em'
}

export interface ContentPlanItem {
  purpose: string; // MỤC ĐÍCH
  topic: string; // CHỦ ĐỀ
  note: string; // GHI CHÚ
  title: string; // TIÊU ĐỀ
  content: string; // NỘI DUNG CHI TIẾT
  visuals: string; // HÌNH ẢNH/VIDEO
  designBrief: string; // BRIEF DESIGN
  hashtags: string; // HASHTAG
}

export interface GeneratorSettings {
  category: ContentCategory;
  count: number;
  customPrompt: string;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ContentCategory, ContentPlanItem } from "../types";

const DENTAL_CONTENT_GUIDE = `
Bạn là một chuyên gia Content Marketing cho ngành Nha khoa. Nhiệm vụ của bạn là lập kế hoạch nội dung chi tiết.
Dựa trên các nhóm bài viết sau:

1. Nhóm bài viết về Dịch vụ (Service Pages): Giới thiệu dịch vụ (Niềng răng, Implant...), Phân tích ưu nhược điểm, Quy trình, Đối tượng phù hợp.
2. Nhóm bài viết về Bệnh lý & Triệu chứng (Educational/Symptom): Giải mã triệu chứng (chảy máu, ê buốt), Kiến thức bệnh lý (sâu răng, nha chu), Hậu quả không điều trị.
3. Nhóm bài viết về Chi phí & Khuyến mãi (Cost & Promo): Bảng giá, Trả góp, So sánh chi phí, Chương trình khuyến mãi.
4. Nhóm bài viết "Người thật việc thật" (Social Proof): Case Study, Feedback khách hàng, Nhật ký điều trị.
5. Nhóm bài viết Hướng dẫn chăm sóc tại nhà (Tips & Tricks): Vệ sinh răng miệng, Chế độ ăn uống, Mẹo vặt chữa đau/trắng răng.
6. Nhóm bài viết về Thương hiệu & Đội ngũ (Brand Authority): Profile bác sĩ, Cơ sở vật chất, Hoạt động phòng khám.
7. Nhóm bài viết Hỏi đáp (Q&A): FAQ, Góc chuyên gia, Phá bỏ lầm tưởng.
8. Nhóm bài viết Nha khoa trẻ em (Pediatric Dentistry): Độ tuổi thay răng, Tiền chỉnh nha, Tâm lý trẻ em.

Yêu cầu về văn phong:
- Hình ảnh mô tả chân thực, tránh máu me.
- Ngôn ngữ chuyên môn đơn giản, dễ hiểu.
- Luôn có CTA (Call To Action) cuối bài.
- Chuẩn SEO.
`;

const responseSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      purpose: { type: Type.STRING, description: "Mục đích của bài viết (Thuộc nhóm nào)" },
      topic: { type: Type.STRING, description: "Chủ đề chính của bài viết" },
      note: { type: Type.STRING, description: "Ghi chú đặc biệt cho bài viết (nếu có)" },
      title: { type: Type.STRING, description: "Tiêu đề bài viết hấp dẫn, chuẩn SEO" },
      content: { type: Type.STRING, description: "Nội dung chi tiết của bài viết, bao gồm cả emoji và CTA" },
      visuals: { type: Type.STRING, description: "Mô tả chi tiết về Hình ảnh hoặc Video cần có" },
      designBrief: { type: Type.STRING, description: "Hướng dẫn thiết kế (Tone màu, font chữ, bố cục)" },
      hashtags: { type: Type.STRING, description: "Các hashtag phù hợp" },
    },
    required: ["purpose", "topic", "title", "content", "visuals", "designBrief", "hashtags"],
  },
};

export const generateContentPlan = async (
  count: number,
  category: ContentCategory,
  customPrompt: string
): Promise<ContentPlanItem[]> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing in environment variables.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    Hãy viết ${count} bài content cho nha khoa.

    Tập trung vào nhóm chủ đề: ${category}.
    ${category === ContentCategory.ALL ? "Hãy phân bổ đều các nhóm chủ đề để đa dạng nội dung." : ""}

    Lưu ý bổ sung từ người dùng: ${customPrompt}

    Hãy trả về kết quả dưới dạng JSON Array theo đúng Schema đã định nghĩa.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        { role: "user", parts: [{ text: DENTAL_CONTENT_GUIDE + "\n" + prompt }] },
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.7, // Creativity balance
      },
    });

    const jsonText = response.text;
    if (!jsonText) return [];

    const data = JSON.parse(jsonText) as ContentPlanItem[];
    return data;

  } catch (error) {
    console.error("Error generating content:", error);
    throw error;
  }
};

import React from 'react';
import { ContentCategory, GeneratorSettings } from '../types';

interface InputPanelProps {
  settings: GeneratorSettings;
  setSettings: React.Dispatch<React.SetStateAction<GeneratorSettings>>;
  onGenerate: () => void;
  isLoading: boolean;
}

const InputPanel: React.FC<InputPanelProps> = ({ settings, setSettings, onGenerate, isLoading }) => {

  const handleChange = (field: keyof GeneratorSettings, value: any) => {
    setSettings(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100 mb-8">
      <div className="grid grid-cols-1 md:grid-cols-12 gap-6">

        {/* Category Selection */}
        <div className="md:col-span-4">
          <label className="block text-sm font-semibold text-gray-700 mb-2">
            Nhóm bài viết
          </label>
          <select
            className="w-full px-4 py-2.5 rounded-lg border border-gray-300 focus:ring-2 focus:ring-dental-500 focus:border-transparent outline-none transition-all"
            value={settings.category}
            onChange={(e) => handleChange('category', e.target.value as ContentCategory)}
          >
            {Object.values(ContentCategory).map((cat) => (
              <option key={cat} value={cat}>
                {cat}
              </option>
            ))}
          </select>
        </div>

        {/* Count Selection */}
        <div className="md:col-span-2">
          <label className="block text-sm font-semibold text-gray-700 mb-2">
            Số lượng bài
          </label>
          <input
            type="number"
            min={1}
            max={20}
            className="w-full px-4 py-2.5 rounded-lg border border-gray-300 focus:ring-2 focus:ring-dental-500 focus:border-transparent outline-none transition-all"
            value={settings.count}
            onChange={(e) => handleChange('count', parseInt(e.target.value))}
          />
        </div>

        {/* Custom Prompt */}
        <div className="md:col-span-6">
          <label className="block text-sm font-semibold text-gray-700 mb-2">
            Ghi chú / Yêu cầu thêm (Prompt)
          </label>
          <textarea
            className="w-full px-4 py-2.5 rounded-lg border border-gray-300 focus:ring-2 focus:ring-dental-500 focus:border-transparent outline-none transition-all h-[46px] min-h-[46px] resize-none overflow-hidden focus:h-24 focus:absolute focus:z-10 focus:shadow-lg"
            placeholder="VD: Tập trung vào niềng răng Invisalign, giọng văn hài hước..."
            value={settings.customPrompt}
            onChange={(e) => handleChange('customPrompt', e.target.value)}
            style={{ transition: 'height 0.2s' }}
          />
        </div>
      </div>

      <div className="mt-6 flex justify-end">
        <button
          onClick={onGenerate}
          disabled={isLoading}
          className={`
            px-8 py-3 rounded-lg font-bold text-white shadow-lg transform transition-all
            ${isLoading 
              ? 'bg-gray-400 cursor-not-allowed' 
              : 'bg-gradient-to-r from-dental-600 to-dental-500 hover:from-dental-700 hover:to-dental-600 hover:scale-[1.02] active:scale-95'
            }
          `}
        >
          {isLoading ? (
            <span className="flex items-center gap-2">
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Đang viết bài...
            </span>
          ) : (
            "Lên kế hoạch ngay ✨"
          )}
        </button>
      </div>
    </div>
  );
};

export default InputPanel;

