import React, { useState } from 'react';
import { ContentCategory, ContentPlanItem, GeneratorSettings } from './types';
import InputPanel from './components/InputPanel';
import PlanTable from './components/PlanTable';
import { generateContentPlan } from './services/geminiService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<GeneratorSettings>({
    category: ContentCategory.ALL,
    count: 5,
    customPrompt: '',
  });

  const [planItems, setPlanItems] = useState<ContentPlanItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    setLoading(true);
    setError(null);
    try {
      const result = await generateContentPlan(
        settings.count,
        settings.category,
        settings.customPrompt
      );
      setPlanItems(result);
    } catch (err: any) {
      setError(err.message || "Đã có lỗi xảy ra khi tạo nội dung. Vui lòng thử lại.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-dental-600 w-10 h-10 rounded-lg flex items-center justify-center text-white text-xl shadow-md">
              🦷
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900 tracking-tight">Dental AI Planner</h1>
              <p className="text-xs text-gray-500">Trợ lý viết nội dung nha khoa tự động</p>
            </div>
          </div>
          <div className="hidden sm:block">
            <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-medium bg-green-100 text-green-800">
              Gemini 3 Pro Active
            </span>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow p-4 sm:p-6 lg:p-8 max-w-[1920px] mx-auto w-full flex flex-col">

        {/* Controls */}
        <InputPanel 
          settings={settings} 
          setSettings={setSettings} 
          onGenerate={handleGenerate}
          isLoading={loading}
        />

        {/* Error Message */}
        {error && (
          <div className="bg-red-50 border-l-4 border-red-500 p-4 mb-6 rounded-r-lg">
            <div className="flex">
              <div className="flex-shrink-0">
                <svg className="h-5 w-5 text-red-400" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                </svg>
              </div>
              <div className="ml-3">
                <p className="text-sm text-red-700">{error}</p>
              </div>
            </div>
          </div>
        )}

        {/* Results Table */}
        <div className="flex-grow">
          <PlanTable items={planItems} />
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-gray-200 mt-auto">
        <div className="max-w-7xl mx-auto py-6 px-4 sm:px-6 lg:px-8 text-center text-sm text-gray-500">
          <p>© {new Date().getFullYear()} Dental AI Content Planner. Powered by Google Gemini.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

