      note: { type: Type.STRING, description: "Ghi chú đặc biệt cho bài viết (nếu có)" },
      title: { type: Type.STRING, description: "Tiêu đề bài viết hấp dẫn, chuẩn SEO" },
      content: { type: Type.STRING, description: "Nội dung chi tiết của bài viết, bao gồm cả emoji và CTA (KHÔNG bao gồm chữ ký cuối)" },
      visuals: { type: Type.STRING, description: "Mô tả chi tiết về Hình ảnh hoặc Video cần có" },
      designBrief: { type: Type.STRING, description: "Hướng dẫn thiết kế (Tone màu, font chữ, bố cục) hoặc hướng dẫn chụp ảnh" },
      hashtags: { type: Type.STRING, description: "Các hashtag phù hợp" },
    },
    required: ["purpose", "topic", "title", "content", "visuals", "designBrief", "hashtags"],
  },
};

export const generateContentPlan = async (
  settings: GeneratorSettings
): Promise<ContentPlanItem[]> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing in environment variables.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    Hãy viết ${settings.count} bài content cho nha khoa.

    Tập trung vào nhóm chủ đề: ${settings.category}.
    ${settings.category === ContentCategory.ALL ? "Hãy phân bổ đều các nhóm chủ đề để đa dạng nội dung." : ""}

    YÊU CẦU VỀ ĐỊNH DẠNG & HÌNH ẢNH (Quan trọng):
    1. Tỷ lệ Video vs Hình ảnh: Khoảng ${settings.videoPercentage}% số bài viết nên định hướng làm VIDEO (Reels/TikTok), còn lại ${100 - settings.videoPercentage}% là HÌNH ẢNH.
    2. Phong cách Visual: Trong các bài hình ảnh, hãy hướng dẫn sao cho khoảng ${settings.designPercentage}% là HÌNH THIẾT KẾ (Banner/Graphic), và ${100 - settings.designPercentage}% là HÌNH ẢNH THỰC TẾ (Chụp tại phòng khám).

    Lưu ý bổ sung từ người dùng: ${settings.customPrompt}

    Hãy trả về kết quả dưới dạng JSON Array theo đúng Schema đã định nghĩa.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        { role: "user", parts: [{ text: DENTAL_CONTENT_GUIDE + "\n" + prompt }] },
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.7, // Creativity balance
      },
    });

    const jsonText = response.text;
    if (!jsonText) return [];

    const data = JSON.parse(jsonText) as ContentPlanItem[];

    // Post-process to append the footer
    return data.map(item => ({
      ...item,
      content: item.content + FOOTER_SIGNATURE
    }));

  } catch (error) {
    console.error("Error generating content:", error);
    throw error;
  }
};

