      'DEADLINE': '',
      'ĐỊNH DẠNG': '',
      'TÌNH TRẠNG': 'Pending',
      'TIẾN ĐỘ': '',
      'LINK ẢNH': ''
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Content Plan");

    // Adjust column widths (approximate)
    const wscols = [
      { wch: 5 },  // STT
      { wch: 20 }, // MUC DICH
      { wch: 25 }, // CHU DE
      { wch: 20 }, // GHI CHU
      { wch: 40 }, // TIEU DE
      { wch: 60 }, // NOI DUNG
      { wch: 30 }, // HINH ANH
      { wch: 30 }, // DESIGN
      { wch: 20 }, // HASHTAG
    ];
    worksheet['!cols'] = wscols;

    XLSX.writeFile(workbook, `Ke_Hoach_Content_Nha_Khoa_${new Date().toISOString().slice(0, 10)}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
