const getTonePrompt = (tone: string) => {
  switch (tone) {
    case 'expert': return "Ưu tiên giọng văn Chuyên gia, Uy tín, Khoa học nhưng vẫn dễ hiểu.";
    case 'friendly': return "Ưu tiên giọng văn Thân thiện, Nhẹ nhàng, như đang tâm tình với khách hàng.";
    case 'trendy': return "Ưu tiên giọng văn Hài hước, Trẻ trung, Bắt trend mạng xã hội.";
    default: return "Sử dụng linh hoạt các giọng văn khác nhau (Chuyên gia, Thân thiện, Hài hước) tùy thuộc vào từng chủ đề cụ thể để tạo sự đa dạng.";
  }
};

const getAudiencePrompt = (audience: string) => {
  switch (audience) {
    case 'genz': return "Tập trung vào đối tượng Gen Z (Học sinh, sinh viên, người mới đi làm).";
    case 'office': return "Tập trung vào đối tượng Dân văn phòng (Có thu nhập, bận rộn, quan tâm thẩm mỹ).";
    case 'older': return "Tập trung vào đối tượng Người trung niên & Cao tuổi (Quan tâm sức khỏe ăn nhai, Implant).";
    case 'parents': return "Tập trung vào đối tượng Phụ huynh (Quan tâm đến răng miệng con cái).";
    default: return "Hướng đến đa dạng các nhóm khách hàng khác nhau cho từng bài viết để phủ rộng thị trường.";
  }
};

const getLengthPrompt = (length: string) => {
  switch (length) {
    case 'short': return "Viết ngắn gọn, súc tích (dạng caption Instagram/Facebook), tập trung vào ảnh/video.";
    case 'medium': return "Độ dài vừa phải, đầy đủ thông tin nhưng không quá dài dòng.";
    case 'long': return "Viết chi tiết, chuyên sâu (dạng bài blog/kiến thức), giải thích cặn kẽ vấn đề.";
    default: return "Độ dài bài viết đa dạng: Có bài ngắn gọn (tương tác), có bài chuyên sâu (kiến thức) đan xen nhau.";
  }
};

const getDistributionPrompt = (settings: GeneratorSettings) => {
  if (settings.category !== ContentCategory.ALL) return "";

  let distPrompt = "PHÂN BỔ TỶ LỆ CÁC LOẠI BÀI VIẾT (Ước lượng mong muốn của người dùng):\n";
  let hasCustom = false;

  CATEGORY_LIST.forEach(cat => {
    const weight = settings.purposeWeights[cat];
    if (weight !== undefined) {
       distPrompt += `- ${SHORT_CATEGORY_NAMES[cat]}: Khoảng ${weight}%\n`;
       hasCustom = true;
    }
  });

  return hasCustom ? distPrompt : "";
};

export const generateContentPlan = async (
  settings: GeneratorSettings
): Promise<ContentPlanItem[]> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing in environment variables.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    Hãy viết ${settings.count} bài content cho nha khoa.

    1. PHẠM VI CHỦ ĐỀ & PHÂN BỔ:
    Tập trung vào nhóm: ${settings.category}.
    ${settings.category === ContentCategory.ALL ? "Hãy phân bổ các nhóm chủ đề để đa dạng nội dung theo tỷ lệ bên dưới." : ""}
    ${getDistributionPrompt(settings)}
    (Lưu ý: Nếu tổng tỷ lệ không tròn 100%, hãy tự cân đối hợp lý để có kế hoạch đa dạng nhất).

    2. ĐỊNH DẠNG VISUAL:
    - Tỷ lệ Video vs Hình ảnh: Khoảng ${settings.videoPercentage}% là VIDEO, còn lại ${100 - settings.videoPercentage}% là HÌNH ẢNH.
    - Phong cách Visual: Khoảng ${settings.designPercentage}% là HÌNH THIẾT KẾ (Banner/Graphic), ${100 - settings.designPercentage}% là HÌNH ẢNH THỰC TẾ.

    3. PHONG CÁCH VIẾT (Tone & Mood):
    - ${getTonePrompt(settings.tone)}
    - ${getAudiencePrompt(settings.targetAudience)}
    - ${getLengthPrompt(settings.postLength)}

    4. LƯU Ý QUAN TRỌNG TỪ NGƯỜI DÙNG:
    "${settings.customPrompt}"

    5. KIẾN THỨC CHUYÊN MÔN & SỰ THẬT Y KHOA (BẮT BUỘC):
    "${settings.knowledgeBase}"
    (TUYỆT ĐỐI tuân thủ các thông tin y khoa, giá cả và quy trình được cung cấp ở trên. Sử dụng chúng làm cơ sở sự thật để viết bài, tránh bịa đặt sai lệch kiến thức chuyên môn).

    6. YÊU CẦU ĐẶC BIỆT:
    - Các thông số trên là định hướng. Hãy linh hoạt điều chỉnh cho phù hợp với từng chủ đề cụ thể để nội dung TỰ NHIÊN và KHÔNG RẬP KHUÔN.
    - Hãy trả về kết quả dưới dạng JSON Array theo đúng Schema đã định nghĩa.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        { role: "user", parts: [{ text: DENTAL_CONTENT_GUIDE + "\n" + prompt }] },
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.75, // Slightly increased for more creativity/diversity
      },
    });

    const jsonText = response.text;
    if (!jsonText) return [];

    const data = JSON.parse(jsonText) as ContentPlanItem[];

    // Post-process to append the footer
    return data.map(item => ({
      ...item,
      content: item.content + FOOTER_SIGNATURE
    }));

  } catch (error) {
    console.error("Error generating content:", error);
    throw error;
  }
};
